INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '헬프 포스터 URL', '헬프 ! ', 'U', TO_DATE('1965.07.29', 'YYYY.MM.DD'), 'GB', 92, 'Stop worrying! HELP! is on the way!', '우연히 암흑의 여왕에 바쳐지는 제물이 된 링고를 구하기 위해 비틀즈 멤버들이 고군분투한다.', 'HELP!', '개봉됨', '영어', 1500000, NULL);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '케데헌2 URL', 'Untitled Kpop Demon Hunters Sequel', '', TO_DATE('', 'YYYY.MM.DD'), '', NULL, '', 'The second installment in the franchise. Plot TBA.', '', '제작 예정', '영어', NULL, NULL);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '첸쏘맨 URL', '극장판 체인소 맨 : 레제편', '15', TO_DATE('2025.09.24', 'YYYY.MM.DD'), 'KR', 100, '아무도 모르는, 소녀의 마음 ', '데블 헌터로 일하는 소년 ‘덴지’는 조직의 배신으로 죽음에 내몰린 순간 전기톱 악마견 ‘포치타’와의 계약으로 하나로 합쳐져 누구도 막을 수 없는 존재 ‘체인소 맨’으로 다시 태어난다. 악마와 사냥꾼, 그리고 정체불명의 적들이 얽힌 잔혹한 전쟁 속에서 ‘레제’라는 이름의 미스터리한 소녀가 ‘덴지’ 앞에 나타나는데… ‘덴지’는 사랑이라는 감정에 이끌려 지금껏 가장 위험한 배틀에 몸을 던진다!', '劇場版 チェンソーマン レゼ篇', '개봉됨', '일본어', 4100000, 174502910);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '토마토 URL', '토마토 공격대', 'PG', TO_DATE('1978.10.04', 'YYYY.MM.DD'), 'US', 87, 'A new musical-comedy-horror show!', '식탁에 있던 토마토들이 어느 날 갑자기 사람들을 공격하기 시작하면서 토마토와 인간은 한바탕 전쟁을 벌이기 시작한다!', 'Attack of the Killer Tomatoes!', '개봉됨', '영어', 100420, 567000);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '바스터즈 URL', '바스터즈: 거친 녀석들', '18', TO_DATE('2009.10.28', 'YYYY.MM.DD'), 'KR', 152, '가장 쿨한 녀석들의 통쾌한 복수', '2차 세계 대전, 나치의 잔인하고 폭력적인 행태에 분개한 미군 알도 레인 중위는 당한 만큼 돌려준다는 강렬한 신념으로 최고의 재능을 가진 8명의 대원을 모아 바스터즈란 군단을 만들어 나치가 점령한 프랑스에 잠입해 복수를 시작한다. 어느 날 알도 레인 중위는 독일의 여배우이자 영국의 더블 스파이인 브리짓에게 뜻밖의 소식을 듣는다. 나치 수뇌부가 모두 참석하는 독일 전쟁 영화의 프리미어에 히틀러도 참석을 한다는 것. 한 번에 나치를 모두 쓸어버릴 계획으로 바스터즈는 이탈리아 영화 관계자로 분장해 극장으로 향하는데...', 'Inglourious Basterds', '개봉됨', '영어', 70000000, 321457747);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '익스트렉션 URL', '익스트랙션', '19', TO_DATE('2020.04.24', 'YYYY.MM.DD'), 'KR', 116, ' When the mission ends, redemption begins', '어떤 일에도 쉽게 동요하지 않는 냉철한 청부업자. 그가 살아남기 위해 자신을 끊임없이 성찰한다. 마약왕의 납치된 아들을 구하러 간 방글라데시에서 그 모든 것이 시작됐다.', 'Extraction', '개봉됨', '영어', 65000000, NULL);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '1917 URL', '1917', '15', TO_DATE('2020.02.19', 'YYYY.MM.DD'), 'KR', 119, '그들이 싸워야 할 것은 적이 아니라 시간이었다', '제1차 세계대전이 한창인 1917년 4월 6일. 독일군에 의해 모든 통신망이 파괴된 상황 속에서 서부전선의 영국군 병사 스코필드와 블레이크에게 하나의 미션이 주어졌다. 독일군의 함정에 빠진 영국군 부대의 수장 매켄지 중령에게 에린무어 장군의 공격 중지 명령을 전달하라는 것. 블레이크는 데본셔 연대에 있는 형을 구하기 위해 기꺼이 임무를 수행한다. 동료인 스코필드는 처음엔 당황스러워하지만 이내 1600명의 동료들을 구하기 위해 전쟁터 한가운데를 가로지르는 여정에 동참한다.', '', '개봉됨', '영어', 100000000, 446064352);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '인셉션 URL ', '인셉션', '12', TO_DATE('2010.07.21', 'YYYY.MM.DD'), 'KR', 148, '생각을 훔치는 거대한 전쟁', '타인의 꿈에 들어가 생각을 훔치는 특수 보안요원 코브. 그를 이용해 라이벌 기업의 정보를 빼내고자 하는 사이토는 코브에게 생각을 훔치는 것이 아닌, 생각을 심는 ‘인셉션’ 작전을 제안한다. 성공 조건으로 국제적인 수배자가 되어있는 코브의 신분을 바꿔주겠다는 거부할 수 없는 제안을 하고, 사랑하는 아이들에게 돌아가기 위해 그 제안을 받아들인다. 최강의 팀을 구성, 표적인 피셔에게 접근해서 ‘인셉션’ 작전을 실행하지만 예기치 못한 사건들과 마주하게 되는데… 꿈 VS 현실! 시간, 규칙, 타이밍 모든 것이 완벽해야만 하는, 단 한 번도 성공한 적 없는 ‘인셉션’ 작전이 시작된다!', 'Inception', '개봉됨', '영어', 160000000, 839030630);
INSERT INTO MOVIES (MOVIE_ID, POSTER_URL, TITLE, MOVIE_RATING, OPEN_DATE, OPEN_COUNTRY, RUNNING_TIME, INTRODUCE, SYNOPSIS, ORIGNAL_TITLE, STATE, "LANGUAGE", BUDGET, PROFIT) VALUES ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, 0), '존 윅 URL', '존 윅', '19', TO_DATE('2015.01.21', 'YYYY.MM.DD'), 'KR', 101, '그를 건드리지 말았어야 했다', '전설이라 불리던 킬러 존 윅은 사랑하는 여인을 만나 결혼을 하면서 범죄의 세계에서 은퇴한다. 행복도 잠시, 투병 끝에 부인이 세상을 떠나고 그의 앞으로 부인이 죽기 전에 보낸 강아지 한 마리가 선물로 배달된다. 어느 날 그의 차를 탐낸 러시아 마피아의 일원 요세프가 존 윅을 폭행하고 애완견 데이지마저 죽여버리는 일이 벌어진다. 그런데 요세프는 과거 존 윅을 고용한 적 있는 러시아 마피아 보스 비고의 아들이다. 마지막 남은 애완견마저 잃은 존 윅은 이제 그만의 방식으로 복수를 시작하는데...', 'John Wick', '개봉됨', '영어', 20000000, 88761661);
